package co.istad.makara.account.rest.exception;import co.istad.makara.account.domain.exception.AccountDomainException;import co.istad.makara.common.application.exception.ApplicationException;import co.istad.makara.common.application.exception.ErrorResponse;import co.istad.makara.common.domain.exception.DomainException;import lombok.extern.slf4j.Slf4j;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.ExceptionHandler;import org.springframework.web.bind.annotation.RestControllerAdvice;import java.time.ZonedDateTime;@RestControllerAdvice@Slf4jpublic class AccountException {    @ExceptionHandler(DomainException.class)    public ResponseEntity<?> handleDomainException(DomainException ex) {        log.error("Domain exception: {}", ex.getMessage());        ErrorResponse error = ErrorResponse.builder()                .status(HttpStatus.INTERNAL_SERVER_ERROR.getReasonPhrase())                .code(HttpStatus.INTERNAL_SERVER_ERROR.value())                .message(ex.getMessage())                .timestamp(ZonedDateTime.now())                .build();        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error);    }}